import{_ as c,C as d,o as r,c as u,a2 as a,b as i,w as t,a as s,E as n,a3 as l}from"./chunks/framework.BQYy9lcq.js";const b=JSON.parse('{"title":"Handling Attribute Groups Directly","description":"","frontmatter":{},"headers":[],"relativePath":"implementation/direct-load.md","filePath":"implementation/direct-load.md","lastUpdated":1779974431000}'),p={name:"implementation/direct-load.md"};function h(f,e,A,g,m,C){const o=d("Mermaid");return r(),u("div",null,[e[2]||(e[2]=a('<h1 id="handling-attribute-groups-directly" tabindex="-1">Handling Attribute Groups Directly <a class="header-anchor" href="#handling-attribute-groups-directly" aria-label="Permalink to &quot;Handling Attribute Groups Directly&quot;">​</a></h1><p>TORCH distinguishes between directly loaded and referenced attributeGroups, where referenced attributeGroups are identified by the flag <code>IncludeReferenceOnly</code>. Directly loaded attributeGroups can be loaded directly as their inclusion in the extraction does not depend on any referencing.</p><p>TORCH loads all resources of the directly loaded attributeGroups based on the Fhir Profile specified in the attribute group and the filters applied to the attribute group. I.e. resources are loaded based on the Fhir Profile specified in the attribute group and the <a href="./../crtdl/filter.html">filters</a> applied to the attribute group.</p><p>The processing has two separate workflows due to the different nature of the resources:</p><ol><li><strong>Core Resources</strong>: These are resources that are outside the patient compartment (no direct link to Patient - e.g. Medication).</li><li><strong>Patient Resources</strong>: These are resources that are directly loaded and processed for each patient.</li></ol><h2 id="_1-directly-loaded-core-attribute-groups" tabindex="-1">1. Directly Loaded Core Attribute Groups <a class="header-anchor" href="#_1-directly-loaded-core-attribute-groups" aria-label="Permalink to &quot;1. Directly Loaded Core Attribute Groups&quot;">​</a></h2><p>Core attributes are simply loaded and processed in a single step.</p><p>This means that all resources that are part of the core attribute group are loaded and processed in a single fhir search request.</p><ul><li>After that a profile and must-have check is done on the resources. <ul><li>Must-have conditions are violated if <strong>not a single</strong> resource passes this check.</li></ul></li><li>If any <strong>must-have</strong> condition is violated, the extraction is fully stopped for the job.</li><li>At the same time it is sufficient if the must-have conditions are fulfilled for a single &quot;global&quot; resource.</li></ul>',9)),(r(),i(l,null,{default:t(()=>[n(o,{id:"mermaid-57",class:"mermaid",graph:"flowchart%20TD%0A%09Start%5BStart%20Core%20Attribute%20Processing%5D%20--%3E%20Load%5BLoad%20all%20core%20resources%20in%20single%20FHIR%20search%20request%5D%0A%09Load%20--%3E%20Profile%5BProfile%20check%20on%20resources%5D%0A%09Profile%20--%3E%20MustHave%5BMust-have%20check%20on%20resources%5D%0A%09MustHave%20--%3E%20Check%7BAny%20must-have%20condition%20violated%3F%7D%0A%09Check%20--%3E%7Cyes%7C%20Stop%5BStop%20extraction%20for%20job%5D%0A%20%20%20%20Check%20--%3E%7Cno%7C%20Global%5BAt%20least%20one%20resource%20fulfills%20must-have%20condition%5D%0A%09Global%20--%3E%20Complete%5BCore%20processing%20complete%5D%0A%09style%20Stop%20fill%3A%20%23ffcccc%0A%09style%20Complete%20fill%3A%20%23ccffcc%0A%20%20%20%20style%20CoreWorkflow%20fill%3A%20%23e1f5fe%0A"})]),fallback:t(()=>[...e[0]||(e[0]=[s(" Loading... ",-1)])]),_:1})),e[3]||(e[3]=a('<h2 id="_2-directly-loaded-patient-attribute-groups" tabindex="-1">2. Directly Loaded Patient Attribute Groups <a class="header-anchor" href="#_2-directly-loaded-patient-attribute-groups" aria-label="Permalink to &quot;2. Directly Loaded Patient Attribute Groups&quot;">​</a></h2><p>Patient attribute groups are loaded and processed for each patient.</p><p>All resources from a patient attribute group are loaded and processed in a single fhir search request and then assigned to their patient.</p><ul><li><p>First the consent is checked for each of the loaded resources and only resources that pass the consent check are processed further.</p><ul><li>When <strong>no consent</strong> key is defined, all resources are considered to be consenting by default.</li></ul></li><li><p>A profile and must-have check is done on every resource.</p></li><li><p>If after the group processing a must-have condition is violated, the respective patient is marked for deletion. Once all patients are processed, all resources (including the patient resource itself) for a patient marked for deletion are deleted. If no resources are left the whole batch is deleted.</p></li></ul>',4)),(r(),i(l,null,{default:t(()=>[n(o,{id:"mermaid-91",class:"mermaid",graph:"flowchart%20TD%0A%09Start%5BStart%20Patient%20Attribute%20Processing%5D%20--%3E%20ForEach%5BFor%20each%20patient%5D%0A%09ForEach%20--%3E%20Load%5BLoad%20patient%20resources%20in%20single%20FHIR%20search%20request%5D%0A%09Load%20--%3E%20Assign%5BAssign%20resources%20to%20patient%5D%0A%09Assign%20--%3E%20Consent%5BConsent%20check%20on%20patient%20resources%5D%0A%09Consent%20--%3E%20ConsentKey%7BConsent%20key%20defined%3F%7D%0A%09ConsentKey%20--%3E%7Cno%7C%20AllConsent%5BAll%20resources%20considered%20consenting%20by%20default%5D%0A%09ConsentKey%20--%3E%7Cyes%7C%20OnlyConsent%5BProcess%20only%20consenting%20resources%5D%0A%09AllConsent%20--%3E%20ProfileCheck%5BProfile%20and%20must-have%20check%20on%20every%20resource%5D%0A%09OnlyConsent%20--%3E%20ProfileCheck%0A%20%20%20%20ProfileCheck%20--%3E%20MustHaveViolated%7BGroup%20processing%20violated%20must-have%20condition%3F%7D%0A%09MustHaveViolated%20--%3E%7Cyes%7C%20MarkDelete%5BMark%20patient%20for%20deletion%5D%0A%09MustHaveViolated%20--%3E%7Cno%7C%20PatientComplete%5BPatient%20processing%20complete%5D%0A%09MarkDelete%20--%3E%20MorePatients%7BMore%20patients%20to%20process%3F%7D%0A%09PatientComplete%20--%3E%20MorePatients%0A%09MorePatients%20--%3E%7Cyes%7C%20ForEach%0A%09MorePatients%20--%3E%7Cno%7C%20DeleteMarked%5BDelete%20marked%20patient%20resources%20from%20batch%5D%0A%09DeleteMarked%20--%3E%20AnyLeft%7BAny%20patients%20left%20in%20batch%3F%7D%0A%09AnyLeft%20--%3E%7Cno%7C%20DeleteBatch%5BDelete%20entire%20batch%5D%0A%09AnyLeft%20--%3E%7Cyes%7C%20BatchComplete%5BBatch%20processing%20complete%5D%0A%09style%20MarkDelete%20fill%3A%20%23ffeeaa%0A%09style%20DeleteBatch%20fill%3A%20%23ffcccc%0A%09style%20BatchComplete%20fill%3A%20%23ccffcc%0A%20%20%20%20style%20PatientWorkflow%20fill%3A%20%23f3e5f5%0A"})]),fallback:t(()=>[...e[1]||(e[1]=[s(" Loading... ",-1)])]),_:1}))])}const D=c(p,[["render",h]]);export{b as __pageData,D as default};
